package support.spring.org.apache.shiro.spring.web.config;

public class AbstractShiroWebFilterConfiguration { @ Autowired protected SecurityManager securityManager ; @ Autowired protected ShiroFilterChainDefinition shiroFilterChainDefinition ; @ Value ( "#{ @environment['shiro.loginUrl'] ?: '/login.jsp' }" ) protected String loginUrl ; @ Value ( "#{ @environment['shiro.successUrl'] ?: '/' }" ) protected String successUrl ; @ Value ( "#{ @environment['shiro.unauthorizedUrl'] ?: null }" ) protected String unauthorizedUrl ; protected ShiroFilterFactoryBean shiroFilterFactoryBean ( ) { ShiroFilterFactoryBean filterFactoryBean = new ShiroFilterFactoryBean ( ) ; filterFactoryBean . setLoginUrl ( loginUrl ) ; filterFactoryBean . setSuccessUrl ( successUrl ) ; filterFactoryBean . setUnauthorizedUrl ( unauthorizedUrl ) ; filterFactoryBean . setSecurityManager ( securityManager ) ; filterFactoryBean . setFilterChainDefinitionMap ( shiroFilterChainDefinition . getFilterChainMap ( ) ) ; return filterFactoryBean ; } }